use clap::{Arg, Command};
use std::process::exit;

fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() == 1 {
        // no arguments
        println!("Error: command is required. Use --help for available commands.");
        exit(1);
    }

    let command = &args[1];

    match command.as_str() {
        "--version" | "--help" | "-v" | "-h" => {
            if command == "--version" || command == "-v" {
                println!("1.0.0");
            } else {
                println!("Usage: executable <command> [options]");
                println!("Available commands:");
                println!("  add <a> <b>        Add two numbers");
                println!("  subtract <a> <b>   Subtract two numbers");
                println!("  multiply <a> <b>   Multiply two numbers");
                println!("  divide <a> <b>     Divide two numbers, error on zero");
                println!("  help              Show this message");
                println!("  --version         Show version");
            }
            return;
        },
        "help" => {
            println!("Usage: executable <command> [options]");
            println!("Available commands:");
            println!("  add <a> <b>        Add two numbers");
            println!("  subtract <a> <b>   Subtract two numbers");
            println!("  multiply <a> <b>   Multiply two numbers");
            println!("  divide <a> <b>     Divide two numbers, error on zero");
            println!("  help              Show this message");
            println!("  --version         Show version");
            return;
        },
        _ => {}
    }

    if args.len() < 4 {
        println!("Error: Two operands are required for '{}'. Exiting.", command);
        exit(1);
    }

    let a_str = &args[2];
    let b_str = &args[3];

    let a: f64 = match a_str.parse() {
        Ok(val) => val,
        Err(_) => {
            println!("Error: Invalid operand: {}", a_str);
            exit(1);
        }
    };

    let b: f64 = match b_str.parse() {
        Ok(val) => val,
        Err(_) => {
            println!("Error: Invalid operand: {}", b_str);
            exit(1);
        }
    };

    match command.as_str() {
        "add" => println!("{}", a + b),
        "subtract" => println!("{}", a - b),
        "multiply" => println!("{}", a * b),
        "divide" => {
            if b == 0.0 {
                println!("Error: division by zero.");
                exit(1);
            }
            println!("{}", a / b);
        },
        _ => {
            println!("Error: '{}' is not a valid command.", command);
            exit(2);
        }
    }
}

