    horizontal := styleChars["horizontal"]
    vertical := styleChars["vertical"]
    topLeft := styleChars["topLeft"]
    topRight := styleChars["topRight"]
    bottomLeft := styleChars["bottomLeft"]
    bottomRight := styleChars["bottomRight"]
    headerSeparatorChar := styleChars["headerSeparator"]
    rowSeparatorChar := styleChars["rowSeparator"]

    // Calculate the full column widths including padding
    colWidths := make([]int, len(maxWidths))
    for i := range colWidths {
        colWidths[i] = maxWidths[i] + 2*padding
    }

    // Build the top border
    var topBorder strings.Builder
    topBorder.WriteString(topLeft)
    for _, width := range colWidths {
        topBorder.WriteString(strings.Repeat(horizontal, width))
        topBorder.WriteString("┬")
    }
    // Replace the final "┬" with topRight
    topBorderString := strings.Replace(topBorder.String(), "┬", topRight, 1)
    topBorderString = strings.Replace(topBorderString, "┬", "┬", len(colWidths)-1)

    // Build the header row
    var headerRow strings.Builder
    headerRow.WriteString(vertical)
    for i, cell := range header {
        formatted := formatCell(cell, maxWidths[i], headerAlign, padding)
        headerRow.WriteString(formatted)
        headerRow.WriteString(vertical)
    }
    headerRowString := headerRow.String()

    // Build header separator
    var headerSeparator strings.Builder
    headerSeparator.WriteString("├")
    for _, width := range colWidths {
        headerSeparator.WriteString(strings.Repeat(headerSeparatorChar, width))
        headerSeparator.WriteString("┼")
    }
    // Replace the final "┼" with "┤"
    headerSeparatorString := strings.Replace(headerSeparator.String(), "┼", "┤", 1)
    headerSeparatorString = strings.Replace(headerSeparatorString, "┼", "┼", len(colWidths)-1)

    // Build body rows
    var bodyRows []string
    for _, row := range body {
        var bodyRow strings.Builder
        bodyRow.WriteString(vertical)
        for i, cell := range row {
            formatted := formatCell(cell, maxWidths[i], bodyAlign, padding)
            bodyRow.WriteString(formatted)
            bodyRow.WriteString(vertical)
        }
        bodyRows = append(bodyRows, bodyRow.String())
    }

    // Build bottom border
    var bottomBorder strings.Builder
    bottomBorder.WriteString(bottomLeft)
    for _, width := range colWidths {
        bottomBorder.WriteString(strings.Repeat(horizontal, width))
        bottomBorder.WriteString("┴")
